# Artificial Hero

A full-screen dark hero with an ASCII-rendered rotating sphere on a GSAP-animated canvas, overlaid with a film grain canvas layer. GSAP ScrollTrigger drives scroll-parallax fade-out of the title and side text. Features glitch effects on the orb.

## Use when
- Building a dark artistic portfolio splash screen with an ASCII animation centerpiece.
- Creating a futuristic product or brand landing page with a cinematic scroll effect.
- Adding a film-grain glitch aesthetic to a hero section.
- Showcasing advanced canvas + GSAP animation capability.

## Stack
- Framework: react
- Libraries: gsap
- Requires: tailwind, shadcn

## Install
```bash
gsap
```

## Component — artificial-hero.tsx
```tsx
import React, { useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

export const Component = () => {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);
  const grainCanvasRef = useRef(null);
  const frameRef = useRef(0);
  const scrollProgressRef = useRef(0);
  const timeRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const grainCanvas = grainCanvasRef.current;
    const ctx = canvas.getContext('2d');
    const grainCtx = grainCanvas.getContext('2d');
    const density = ' .:-=+*#%@';
    const params = { rotation: 0, atmosphereShift: 0, glitchIntensity: 0, glitchFrequency: 0 };

    gsap.to(params, { rotation: Math.PI * 2, duration: 20, repeat: -1, ease: "none" });
    gsap.to(params, { atmosphereShift: 1, duration: 6, repeat: -1, yoyo: true, ease: "sine.inOut" });
    gsap.to(params, { glitchIntensity: 1, duration: 0.1, repeat: -1, yoyo: true, ease: "power2.inOut", repeatDelay: Math.random() * 3 + 1 });
    gsap.to(params, { glitchFrequency: 1, duration: 0.05, repeat: -1, yoyo: true, ease: "none" });

    ScrollTrigger.create({
      trigger: containerRef.current,
      start: "top top",
      end: "bottom top",
      scrub: 1,
      onUpdate: (self) => { scrollProgressRef.current = self.progress; }
    });

    const generateFilmGrain = (width: number, height: number, intensity = 0.15) => {
      const imageData = grainCtx.createImageData(width, height);
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        const grain = (Math.random() - 0.5) * intensity * 255;
        data[i] = Math.max(0, Math.min(255, 128 + grain));
        data[i + 1] = Math.max(0, Math.min(255, 128 + grain));
        data[i + 2] = Math.max(0, Math.min(255, 128 + grain));
        data[i + 3] = Math.abs(grain) * 3;
      }
      return imageData;
    };

    function render() {
      timeRef.current += 0.016;
      const time = timeRef.current;
      const width = canvas.width = grainCanvas.width = window.innerWidth;
      const height = canvas.height = grainCanvas.height = window.innerHeight;
      ctx.fillStyle = '#000';
      ctx.fillRect(0, 0, width, height);
      const centerX = width / 2; const centerY = height / 2;
      const radius = Math.min(width, height) * 0.2;
      const hue = 180 + params.atmosphereShift * 60;
      const bgGradient = ctx.createRadialGradient(centerX, centerY - 50, 0, centerX, centerY, Math.max(width, height) * 0.8);
      bgGradient.addColorStop(0, `hsla(${hue + 40}, 80%, 60%, 0.4)`);
      bgGradient.addColorStop(0.3, `hsla(${hue}, 60%, 40%, 0.3)`);
      bgGradient.addColorStop(0.6, `hsla(${hue - 20}, 40%, 20%, 0.2)`);
      bgGradient.addColorStop(1, 'rgba(0, 0, 0, 0.9)');
      ctx.fillStyle = bgGradient;
      ctx.fillRect(0, 0, width, height);
      ctx.font = '10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      const spacing = 9;
      const cols = Math.floor(width / spacing); const rows = Math.floor(height / spacing);
      for (let i = 0; i < cols && i < 150; i++) {
        for (let j = 0; j < rows && j < 100; j++) {
          const x = (i - cols / 2) * spacing + centerX; const y = (j - rows / 2) * spacing + centerY;
          const dx = x - centerX; const dy = y - centerY;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < radius && Math.random() > 0.4) {
            const z = Math.sqrt(Math.max(0, radius * radius - dx * dx - dy * dy));
            const angle = params.rotation;
            const rotZ = dx * Math.sin(angle) + z * Math.cos(angle);
            const brightness = (rotZ + radius) / (radius * 2);
            if (rotZ > -radius * 0.3) {
              const charIndex = Math.floor(brightness * (density.length - 1));
              ctx.fillStyle = `rgba(255, 255, 255, ${Math.max(0.2, brightness)})`;
              ctx.fillText(density[charIndex], x, y);
            }
          }
        }
      }
      grainCtx.clearRect(0, 0, width, height);
      grainCtx.putImageData(generateFilmGrain(width, height, 0.22 + Math.sin(time * 10) * 0.03), 0, 0);
      frameRef.current = requestAnimationFrame(render);
    }

    render();

    return () => {
      if (frameRef.current) cancelAnimationFrame(frameRef.current);
      ScrollTrigger.getAll().forEach(t => t.kill());
    };
  }, []);

  return (
    <div ref={containerRef} style={{ width: '100%', height: '100%', background: '#000' }}>
      <div style={{ position: 'fixed', bottom: '15%', left: 0, right: 0, zIndex: 50, pointerEvents: 'none' }}>
        <div style={{ fontFamily: 'Arial Black, Arial, sans-serif', fontSize: 'clamp(4rem, 15vw, 12rem)', fontWeight: '900', color: 'white', textAlign: 'center', lineHeight: 0.8, letterSpacing: '-0.02em' }}>
          ARTIFICIAL
        </div>
      </div>
      <div style={{ position: 'sticky', top: 0, width: '100%', height: '100vh' }}>
        <canvas ref={canvasRef} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: '#000' }} />
        <canvas ref={grainCanvasRef} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', mixBlendMode: 'overlay', opacity: 0.6 }} />
      </div>
    </div>
  );
};
```

## Demo
```tsx
import { Component } from "@/components/ui/artificial-hero";

const DemoOne = () => {
  return <Component />;
};

export { DemoOne };
```

## Notes
- Uses `style jsx` in the original source for scoped CSS (requires styled-jsx support). In standard React/Next.js apps without styled-jsx, move the keyframe CSS to a global stylesheet or Tailwind config.
- GSAP `ScrollTrigger` is registered globally — if multiple instances are on the page, call `ScrollTrigger.getAll().forEach(t => t.kill())` carefully to avoid killing other components' triggers.
- The `JetBrains Mono` font is loaded from Google Fonts in the original — add it to your `<head>` or font config for the authentic ASCII look.
